  ('elementary-10ced7e2-moex-00611', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '下列有關公務人員考績之敘述，何者錯誤？', '["公務人員年終考績丁等者，免職", "公務人員另予考績列丁等者，免職", "專案考績一次記二大過者，免職", "各機關考績委員會對於擬予考績列丁等及一次記二大過人員，處分後應給予當事人陳述及申辯之機會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00612', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '依公務人員加給給與辦法規定，有關特定期間加給之支給，下列敘述何者錯誤？', '["死亡當月之加給，按全月支給", "依公務人員請假規則規定期限給假之期間，其加給照常支給", "因奉派執行職務失蹤，在未確定死亡前或依法免職前，原支領之加給照常支給", "請事假已逾規定期限之期間或曠職之期間，其按日扣除之俸給，不包含各種加給"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00613', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '下列何者不是交通事業人員之考成？', '["平時考成", "年終考成", "另予考成", "專案考成"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00614', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '依公務人員俸給法規定，初任各官等職務人員，其等級起敘之敘述，下列何者錯誤？', '["高等考試之一級考試或特種考試之一等考試及格者，初任薦任職務時，敘薦任第九職等本俸一級；先 以薦任第八職等任用者，敘薦任第八職等本俸四級", "高等考試之二級考試或特種考試之二等考試及格者，初任薦任職務時，敘薦任第八職等本俸四級；先 以薦任第七職等任用者，敘薦任第七職等本俸一級", "普通考試或特種考試之四等考試及格者，敘委任第三職等本俸一級", "初等考試或特種考試之五等考試及格者，敘委任第一職等本俸一級"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00615', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '下列何者不屬於公教人員保險法適用的對象？', '["臺北市政府編制內之有給專任人員", "依桃園國際機場股份有限公司人事管理法令進用之從業人員", "臺灣大學編制內之有給專任職員", "教育部核准立案之私立學校編制內之有給專任教師"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00616', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '關於公務員廉政倫理規範，下列敘述何者錯誤？', '["正常社交禮俗標準，指一般人社交往來，可以收受市價不超過新臺幣三千元之財物餽贈", "公務人員可以在偶發而無影響特定權利義務之虞時，得受贈與其職務有利害關係者餽贈財物，但所受 贈之財物市價必須在新臺幣一千元以下", "正常社交禮俗標準，指一般人社交往來，同一年度來自同一來源受贈財物以新臺幣一萬元為限", "與其無職務上利害關係者所為之餽贈，市價超過正常社交禮俗標準時，應於受贈之日起三日內，簽報 其長官，必要時並知會政風機構"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00617', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '某甲因酒駕遭懲戒法院判決降級處分，其幾年內不得陞任主管職務？', '["二年", "三年", "四年", "五年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00618', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '公務人員登記為公職候選人者，應依規定請事假或休假，其應行請假之時期為何？', '["自候選人名單公告之日起至投票日止", "自登記為候選人之日起至投票日止", "自登記為候選人之日起至候選人名單公告之日止", "自登記為候選人之日起至當選人名單公告之日止"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00619', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '公務員受罰款懲戒處分之同時，依公務員懲戒法之規定，得與下列何種懲戒併為處分？', '["剝奪、減少退休金", "降級", "減俸", "免職"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00620', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '透過政制結構途徑推動行政中立的觀念，下列敘述何者最正確？', '["因應未來趨勢，黨政運作應該配合行政事務運作，以提高行政效率", "文官可以透過報備兼任政黨負責人，以提高政治運作效率", "政務官向人民負政治責任，事務官向機關首長負行政責任", "考試委員應超越黨派，依據總統命令行使職權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
